/**
* V5.53: Save all user preferences to Firestore
* Only saves for non-anonymous users
*/
async function saveUserPreferencesToCloud() {
if (state.isUserAnonymous || !state.userId || !state.db) {
    safeLog.log('[CloudSync] Skipping cloud save (anonymous or no user)');
    return;
}

try {
    const prefsDocRef = doc(state.db, 'artifacts', state.appId, 'users', state.userId, 'settings', 'preferences');
    
    // V5.55.6: Removed mutedBellIds from cloud sync - mute status is device-specific
    const prefsData = {
        periodVisualOverrides: state.periodVisualOverrides || {},
        bellSoundOverrides: state.bellSoundOverrides || {},
        bellVisualOverrides: state.bellVisualOverrides || {}, // V5.55.9
        bellNameOverrides: state.bellNameOverrides || {}, // V5.55.9
        periodNameOverrides: state.periodNameOverrides || {},
        warningSettings: state.warningSettings || {},
        kioskModeEnabled: state.kioskModeEnabled || false,
        quickBellDefaultSound: state.quickBellDefaultSound || 'ellisBell.mp3',
        lastUpdated: new Date().toISOString()
    };
    
    await setDoc(prefsDocRef, prefsData, { merge: true });
    safeLog.log('[CloudSync] User preferences saved to cloud');
    
} catch (error) {
    console.error('[CloudSync] Error saving preferences to cloud:', error);
}
}

/**
* V5.53: Load user preferences from Firestore
* Falls back to localStorage if cloud data doesn't exist
*/
async function loadUserPreferencesFromCloud() {
if (state.isUserAnonymous || !state.userId || !state.db) {
    safeLog.log('[CloudSync] Skipping cloud load (anonymous or no user)');
    return false;
}

try {
    const prefsDocRef = doc(state.db, 'artifacts', state.appId, 'users', state.userId, 'settings', 'preferences');
    const docSnap = await getDoc(prefsDocRef);
    
    if (docSnap.exists()) {
        const data = docSnap.data();
        safeLog.log('[CloudSync] Loaded preferences from cloud:', data);
        
        // Apply cloud data to local state
        if (data.periodVisualOverrides) {
            state.periodVisualOverrides = data.periodVisualOverrides;
            localStorage.setItem('periodVisualOverrides', JSON.stringify(state.periodVisualOverrides));
        }
        
        if (data.bellSoundOverrides) {
            state.bellSoundOverrides = data.bellSoundOverrides;
            localStorage.setItem('bellSoundOverrides', JSON.stringify(state.bellSoundOverrides));
        }
        
        // V5.55.9: Load bell visual and name overrides
        if (data.bellVisualOverrides) {
            state.bellVisualOverrides = data.bellVisualOverrides;
            localStorage.setItem('bellVisualOverrides', JSON.stringify(state.bellVisualOverrides));
        }
        
        if (data.bellNameOverrides) {
            state.bellNameOverrides = data.bellNameOverrides;
            localStorage.setItem('bellNameOverrides', JSON.stringify(state.bellNameOverrides));
        }
        
        if (data.periodNameOverrides) {
            state.periodNameOverrides = data.periodNameOverrides;
            localStorage.setItem('periodNameOverrides', JSON.stringify(state.periodNameOverrides));
        }
        
        // V5.55.6: Removed mutedBellIds from cloud sync - mute status is device-specific
        // mutedBellIds stays in localStorage only
        
        if (data.warningSettings) {
            state.warningSettings = { ...state.warningSettings, ...data.warningSettings };
            localStorage.setItem('countdownWarningSettings', JSON.stringify(state.warningSettings));
            // Note: applyWarningColors() called in init() after this completes
        }
        
        if (typeof data.kioskModeEnabled === 'boolean') {
            state.kioskModeEnabled = data.kioskModeEnabled;
            localStorage.setItem('kioskModeEnabled', state.kioskModeEnabled ? 'true' : 'false');
            // Note: applyKioskMode() called in init() after this completes
        }
        
        // V5.55.5: Load quick bell default sound preference
        if (data.quickBellDefaultSound) {
            state.quickBellDefaultSound = data.quickBellDefaultSound;
            state.quickBellSound = state.quickBellDefaultSound;
            localStorage.setItem('quickBellDefaultSound', state.quickBellDefaultSound);
            // Apply to dropdown if it exists
            if (quickBellSoundSelect) {
                quickBellSoundSelect.value = state.quickBellDefaultSound;
            }
        }
        
        return true; // Cloud data was loaded
    } else {
        safeLog.log('[CloudSync] No cloud preferences found, using localStorage');
        // First time user - save current localStorage data to cloud
        await saveUserPreferencesToCloud();
        return false;
    }
    
} catch (error) {
    console.error('[CloudSync] Error loading preferences from cloud:', error);
    return false;
}
}

/**
* V5.53: Set up real-time listener for user preferences
* Syncs changes from other devices
*/
function setupUserPreferencesListener() {
if (state.isUserAnonymous || !state.userId || !state.db) {
    return;
}

// Unsubscribe from previous listener if exists
if (state.userPreferencesListenerUnsubscribe) {
    state.userPreferencesListenerUnsubscribe();
}

const prefsDocRef = doc(state.db, 'artifacts', state.appId, 'users', state.userId, 'settings', 'preferences');

safeLog.log('[CloudSync] Setting up preferences listener...');

state.userPreferencesListenerUnsubscribe = onSnapshot(prefsDocRef, (docSnap) => {
    if (docSnap.exists()) {
        const data = docSnap.data();
        safeLog.log('[CloudSync] Preferences updated from cloud');
        
        // Apply cloud data to local state (same as loadUserPreferencesFromCloud)
        if (data.periodVisualOverrides) {
            state.periodVisualOverrides = data.periodVisualOverrides;
            localStorage.setItem('periodVisualOverrides', JSON.stringify(state.periodVisualOverrides));
        }
        
        if (data.bellSoundOverrides) {
            state.bellSoundOverrides = data.bellSoundOverrides;
            localStorage.setItem('bellSoundOverrides', JSON.stringify(state.bellSoundOverrides));
        }
        
        // V5.55.9: Bell visual and name overrides
        if (data.bellVisualOverrides) {
            state.bellVisualOverrides = data.bellVisualOverrides;
            localStorage.setItem('bellVisualOverrides', JSON.stringify(state.bellVisualOverrides));
        }
        
        if (data.bellNameOverrides) {
            state.bellNameOverrides = data.bellNameOverrides;
            localStorage.setItem('bellNameOverrides', JSON.stringify(state.bellNameOverrides));
        }
        
        if (data.periodNameOverrides) {
            state.periodNameOverrides = data.periodNameOverrides;
            localStorage.setItem('periodNameOverrides', JSON.stringify(state.periodNameOverrides));
        }
        
        // V5.55.6: Removed mutedBellIds from cloud sync - mute status is device-specific
        
        if (data.warningSettings) {
            state.warningSettings = { ...state.warningSettings, ...data.warningSettings };
            localStorage.setItem('countdownWarningSettings', JSON.stringify(state.warningSettings));
            // Colors applied via CSS variables on next warning check
        }
        
        if (typeof data.kioskModeEnabled === 'boolean') {
            state.kioskModeEnabled = data.kioskModeEnabled;
            localStorage.setItem('kioskModeEnabled', state.kioskModeEnabled ? 'true' : 'false');
            // Kiosk mode state updated, will apply on next toggle or refresh
        }
        
        // V5.55.5: Quick bell default sound
        if (data.quickBellDefaultSound) {
            state.quickBellDefaultSound = data.quickBellDefaultSound;
            state.quickBellSound = state.quickBellDefaultSound;
            localStorage.setItem('quickBellDefaultSound', state.quickBellDefaultSound);
            if (quickBellSoundSelect) {
                quickBellSoundSelect.value = state.quickBellDefaultSound;
            }
        }
        
        // Note: Visual changes will apply on next page interaction or refresh
        // Real-time sync updates the data, UI updates on next render cycle
        safeLog.log('[CloudSync] Preferences synced from another device');
    }
}, (error) => {
    console.error('[CloudSync] Error listening to preferences:', error);
});
}

